  sum += sin(dot(ps, DIR_D2) * 8.0 + uPatternTime * 2.2);
  sum += sin(dot(ps, DIR_Y) * 5.5 - uPatternTime * 2.9);
  sum += sin(dot(ps, DIR_2M1) * 9.0 + uPatternTime * 3.7);
